form:Form.form:Scripts:
		function sbInsert_click() {
	var objHtml;
	var strValue;

	strValue = Ctrl("cboAttrs").GetXValue();
	if (strValue == "") return;

	objHtml = Ctrl("t_texto_mail").m_HTMLObject;

	insertAtCursor(objHtml, strValue);

}

function insertAtCursor(myField, myValue) {
	//IE
	if (document.selection) {
		myField.focus();
		myField.value = myField.value + myValue;

	//Mozilla/Firefox/Netscape 7+
	} else if (myField.selectionStart || myField.selectionStart == '0') {

		myField.focus();

		var startPos = myField.selectionStart;
		var endPos = myField.selectionEnd;

		myField.value = myField.value.substring(0, startPos) + myValue + myField.value.substring(endPos, myField.value.length);
		myField.setSelectionRange(endPos+myValue.length, endPos+myValue.length);

		} else {

			myField.value += myValue;
		}
}
